-- ปีงบประมาณ
ON CONFLICT (year_be) DO NOTHING;

-- ============================================================
-- โครงการ (25 โครงการ พร้อมงบประมาณจาก รายงานเงินคงเหลือ)
-- ============================================================
WITH y AS (SELECT id FROM years WHERE year_be = 2569)
ON CONFLICT DO NOTHING;

